#include <vector>
#include <cassert>
using namespace std;

struct BTreeNode {
    int n;                    // current key count
    vector<int> keys;         // sorted keys, size up to 2t-1
    vector<BTreeNode*> c;     // children, size up to 2t (empty for leaves)
    bool leaf;

    explicit BTreeNode(int t, bool isLeaf)
        : n(0), leaf(isLeaf) {
        keys.reserve(2 * t - 1);
        if (!isLeaf) c.reserve(2 * t);
    }
};

struct BTree {
    BTreeNode* root;
    int t;   // minimum degree

    explicit BTree(int minDegree) : t(minDegree) {
        assert(t >= 2);
        root = new BTreeNode(t, true);
    }
};
// B-tree invariants (checked after every operation):
// 1. Every node: keys.size() <= 2t-1
// 2. Every non-root node: keys.size() >= t-1
// 3. Internal node with k keys has k+1 children
// 4. All leaves at same depth
// 5. keys[i] <= keys[i+1] for all i
