// Search for key k starting at node x
// Returns {node, index} or {nullptr, -1} if not found
pair<BTreeNode*, int> bTreeSearch(BTreeNode* x, int k) {
    int i = 0;
    while (i < x->n && k > x->keys[i]) ++i;
    if (i < x->n && k == x->keys[i])
        return {x, i};
    if (x->leaf)
        return {nullptr, -1};
    return bTreeSearch(x->c[i], k);
}

// Split full child x->c[i] (must have 2t-1 keys) while at parent x
void bTreeSplitChild(BTree& T, BTreeNode* x, int i) {
    int t = T.t;
    BTreeNode* z = new BTreeNode(t, x->c[i]->leaf);
    BTreeNode* y = x->c[i];

    // Copy right half of y's keys to z
    for (int j = 0; j < t - 1; ++j)
        z->keys.push_back(y->keys[j + t]);
    // Copy right half of y's children to z (if internal)
    if (!y->leaf)
        for (int j = 0; j < t; ++j)
            z->c.push_back(y->c[j + t]);

    // Trim y to left half
    int medianKey = y->keys[t - 1];
    y->keys.resize(t - 1);
    if (!y->leaf) y->c.resize(t);
    y->n = t - 1;
    z->n = t - 1;

    // Insert z into x's children and median into x's keys
    x->c.insert(x->c.begin() + i + 1, z);
    x->keys.insert(x->keys.begin() + i, medianKey);
    ++x->n;
}

void bTreeInsertNonfull(BTree& T, BTreeNode* x, int k) {
    int i = x->n - 1;
    if (x->leaf) {
        x->keys.push_back(0);
        while (i >= 0 && k < x->keys[i]) {
            x->keys[i + 1] = x->keys[i];
            --i;
        }
        x->keys[i + 1] = k;
        ++x->n;
    } else {
        while (i >= 0 && k < x->keys[i]) --i;
        ++i;
        if (x->c[i]->n == 2 * T.t - 1) {
            bTreeSplitChild(T, x, i);
            if (k > x->keys[i]) ++i;
        }
        bTreeInsertNonfull(T, x->c[i], k);
    }
}

void bTreeInsert(BTree& T, int k) {
    BTreeNode* r = T.root;
    if (r->n == 2 * T.t - 1) {
        BTreeNode* s = new BTreeNode(T.t, false);
        T.root = s;
        s->c.push_back(r);
        bTreeSplitChild(T, s, 0);
        bTreeInsertNonfull(T, s, k);
    } else {
        bTreeInsertNonfull(T, r, k);
    }
}
