// Merge right child c[i+1] into left child c[i] using separator key[i]
void bTreeMergeChildren(BTree& T, BTreeNode* x, int i) {
    int t = T.t;
    BTreeNode* y = x->c[i];
    BTreeNode* z = x->c[i + 1];

    // Pull separator key from x down into y
    y->keys.push_back(x->keys[i]);
    // Copy z's keys into y
    for (int k : z->keys) y->keys.push_back(k);
    // Copy z's children into y (if internal)
    if (!y->leaf)
        for (BTreeNode* child : z->c) y->c.push_back(child);
    y->n = 2 * t - 1;

    // Remove separator key and z pointer from x
    x->keys.erase(x->keys.begin() + i);
    x->c.erase(x->c.begin() + i + 1);
    --x->n;

    delete z;

    // If x is now empty (was root), shrink tree
    if (x->n == 0) {
        T.root = y;
        delete x;
    }
}

// Borrow a key from left sibling c[i-1] into c[i] via parent key[i-1]
void bTreeBorrowFromLeft(BTreeNode* x, int i) {
    BTreeNode* child  = x->c[i];
    BTreeNode* sibling = x->c[i - 1];

    child->keys.insert(child->keys.begin(), x->keys[i - 1]);
    x->keys[i - 1] = sibling->keys.back();
    sibling->keys.pop_back();
    if (!sibling->leaf) {
        child->c.insert(child->c.begin(), sibling->c.back());
        sibling->c.pop_back();
    }
    ++child->n;
    --sibling->n;
}

// Borrow a key from right sibling c[i+1] into c[i] via parent key[i]
void bTreeBorrowFromRight(BTreeNode* x, int i) {
    BTreeNode* child   = x->c[i];
    BTreeNode* sibling = x->c[i + 1];

    child->keys.push_back(x->keys[i]);
    x->keys[i] = sibling->keys.front();
    sibling->keys.erase(sibling->keys.begin());
    if (!sibling->leaf) {
        child->c.push_back(sibling->c.front());
        sibling->c.erase(sibling->c.begin());
    }
    ++child->n;
    --sibling->n;
}

void bTreeDelete(BTree& T, BTreeNode* x, int k) {
    int t = T.t;
    int i = 0;
    while (i < x->n && k > x->keys[i]) ++i;

    if (i < x->n && k == x->keys[i]) {
        // Key is in this node
        if (x->leaf) {                              // Case 1
            x->keys.erase(x->keys.begin() + i);
            --x->n;
        } else {
            BTreeNode* y = x->c[i];
            BTreeNode* z = x->c[i + 1];
            if (y->n >= t) {                        // Case 2a
                // Find predecessor (rightmost leaf in y's subtree)
                BTreeNode* cur = y;
                while (!cur->leaf) cur = cur->c[cur->n];
                int pred = cur->keys.back();
                bTreeDelete(T, y, pred);
                x->keys[i] = pred;
            } else if (z->n >= t) {                 // Case 2b
                BTreeNode* cur = z;
                while (!cur->leaf) cur = cur->c[0];
                int succ = cur->keys.front();
                bTreeDelete(T, z, succ);
                x->keys[i] = succ;
            } else {                                // Case 2c: merge
                bTreeMergeChildren(T, x, i);
                bTreeDelete(T, y, k);
            }
        }
    } else {
        // Key is not here — descend into c[i]
        if (x->leaf) return; // k not in tree
        bool isLastChild = (i == x->n);
        BTreeNode* child = x->c[i];

        if (child->n < t) {                         // Need to ensure >= t keys
            if (i > 0 && x->c[i - 1]->n >= t)
                bTreeBorrowFromLeft(x, i);
            else if (i < x->n && x->c[i + 1]->n >= t)
                bTreeBorrowFromRight(x, i);
            else {
                if (i < x->n)
                    bTreeMergeChildren(T, x, i);
                else {
                    bTreeMergeChildren(T, x, i - 1);
                    --i;
                }
                child = x->c[i]; // merged child
            }
        }
        bTreeDelete(T, child, k);
    }
}
